auto boundFunc1 = std::bind([](int x) {
    std::cout << x << "\n";
}, value);  // ❌ Binds copy of value

value = 20;
boundFunc1();  // Prints 10, not 20

auto boundFunc2 = std::bind([](int& x) {
    std::cout << x << "\n";
}, std::ref(value));  // ✅ Binds reference using std::ref

value = 30;
boundFunc2();  // Prints 30
```

