    int value = 42;
public:
    std::function<void()> getLambda() {
        return [this]() {  // Captures 'this' pointer
            std::cout << value << "\n";  // Accesses this->value
        };
    }
};

// ❌ Dangerous if Widget is destroyed
Widget* w = new Widget();
auto lambda = w->getLambda();
delete w;
lambda();  // UB: accesses deleted object
```

