// More complex: match specific patterns
template<typename... Types>
struct AllPointers;

template<typename T, typename... Rest>
struct AllPointers<T*, Rest...> {
    static constexpr bool value = AllPointers<Rest...>::value;
};

template<>
struct AllPointers<> {
