// Base case: no arguments
void print() {
    std::cout << "\n";
}

// Recursive case
template<typename T, typename... Args>
void print(const T& first, const Args&... rest) {
    std::cout << first;
    if (sizeof...(rest) > 0) {
        std::cout << ", ";
    }
    print(rest...);
}

// Usage
